export async function getAllProducts() {
  // Simulate database delay — real queries against thousands of SKUs
  // take longer, but caching ("products" tag) keeps the admin experience fast.
  await new Promise((resolve) => setTimeout(resolve, 100));

  return [
    { id: 1, sku: "LPT-100", name: "Laptop Pro 15", price: 1499, inventory: 42, available: true },
    { id: 2, sku: "PHN-200", name: "Smartphone X", price: 799, inventory: 128, available: true },
    { id: 3, sku: "TAB-300", name: "Tablet Air", price: 549, inventory: 0, available: false },
    { id: 4, sku: "HDN-400", name: "Noise-Cancelling Headphones", price: 249, inventory: 87, available: true },
    { id: 5, sku: "WCH-500", name: "Smartwatch Pro", price: 349, inventory: 23, available: true },
    { id: 6, sku: "KBD-600", name: "Mechanical Keyboard", price: 129, inventory: 56, available: true },
    { id: 7, sku: "MON-700", name: "27\" 4K Monitor", price: 599, inventory: 0, available: false },
    { id: 8, sku: "MSE-800", name: "Ergonomic Mouse", price: 79, inventory: 194, available: true },
    { id: 9, sku: "SPK-900", name: "Bluetooth Speaker", price: 89, inventory: 34, available: true },
    { id: 10, sku: "CAM-100", name: "Webcam HD", price: 119, inventory: 12, available: true },
  ];
}

/**
 * Simulates pulling refreshed pricing / inventory / availability data
 * from an upstream ERP or PIM system.
 *
 * In production this would call an external API, transform the payload,
 * and upsert into the local product database. The data-import layer is
 * outside the scope of this page — the page only needs to know when to
 * refresh its cache.
 */
export async function syncCatalogFromUpstream() {
  // Simulate network latency to the ERP/PIM system
  await new Promise((resolve) => setTimeout(resolve, 2000));
  return { synced: true, updatedAt: new Date().toISOString() };
}

import { unstable_cache } from "next/cache";
import { getAllProducts } from "@/lib/db";

/**
 * Cached product fetcher.
 *
 * Tagged with "products" so that the admin "Sync latest catalog" action
 * (which calls revalidateTag("products")) invalidates this cache entry.
 * The key ["catalog-products"] differentiates this from other consumers
 * that tag their data with the same "products" tag (e.g. a dashboard
 * widget) so they all invalidate together — "eventual consistency across
 * catalog views."
 */
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ["catalog-products"],
  {
    tags: ["products"],
    /**
     * Fallback revalidation window (5 minutes) in case the explicit
     * sync trigger is not used — admins who just browse the catalog
     * will see data no older than this.
     */
    revalidate: 300,
  }
);

export async function ProductTable() {
  const products = await getCachedProducts();

  if (products.length === 0) {
    return <p className="empty-state">No products found.</p>;
  }

  return (
    <div className="table-wrapper">
      <table>
        <thead>
          <tr>
            <th>SKU</th>
            <th>Name</th>
            <th>Price</th>
            <th>Inventory</th>
            <th>Availability</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id} data-available={product.available}>
              <td className="sku">{product.sku}</td>
              <td>{product.name}</td>
              <td className="price">${product.price}</td>
              <td className="inventory">{product.inventory}</td>
              <td>
                <span
                  className={`badge ${
                    product.available ? "badge--available" : "badge--unavailable"
                  }`}
                >
                  {product.available ? "In Stock" : "Out of Stock"}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      <p className="table-footer">
        Showing {products.length} product{products.length !== 1 ? "s" : ""}
      </p>
    </div>
  );
}

