.catalog-page {
  max-width: 960px;
  margin: 0 auto;
  padding: 2rem 1.5rem;
  font-family: system-ui, -apple-system, sans-serif;
}

/* ── Header ────────────────────────────────────────────────── */

.catalog-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 1.5rem;
  margin-bottom: 1.5rem;
  flex-wrap: wrap;
}

.catalog-header h1 {
  margin: 0 0 0.25rem;
  font-size: 1.5rem;
  font-weight: 600;
}

.subtitle {
  margin: 0;
  color: #666;
  font-size: 0.875rem;
  line-height: 1.5;
  max-width: 36rem;
}

/* ── Buttons ───────────────────────────────────────────────── */

.btn {
  display: inline-flex;
  align-items: center;
  gap: 0.375rem;
  padding: 0.5rem 1rem;
  border: 1px solid #d0d5dd;
  border-radius: 6px;
  background: #fff;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.15s, border-color 0.15s;
}

.btn:hover {
  background: #f5f5f5;
  border-color: #b0b5bd;
}

.btn:active {
  background: #eaeaea;
}

.btn--sync {
  background: #0a2540;
  color: #fff;
  border-color: #0a2540;
}

.btn--sync:hover {
  background: #1a3a5c;
  border-color: #1a3a5c;
}

.btn--sync:active {
  background: #0a1e30;
}

/* ── Success banner ────────────────────────────────────────── */

.banner {
  display: flex;
  align-items: center;
  gap: 0.625rem;
  padding: 0.75rem 1rem;
  border-radius: 6px;
  font-size: 0.875rem;
  margin-bottom: 1.25rem;
}

.banner--success {
  background: #ecfdf5;
  color: #065f46;
  border: 1px solid #a7f3d0;
}

/* ── Table ─────────────────────────────────────────────────── */

.table-wrapper {
  overflow-x: auto;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.875rem;
}

thead {
  background: #f9fafb;
  border-bottom: 2px solid #e5e7eb;
}

th {
  padding: 0.75rem 1rem;
  text-align: left;
  font-weight: 600;
  color: #374151;
  white-space: nowrap;
}

td {
  padding: 0.75rem 1rem;
  border-bottom: 1px solid #f3f4f6;
  color: #1f2937;
}

tr:last-child td {
  border-bottom: none;
}

tr[data-available="false"] {
  opacity: 0.6;
}

/* ── Cell variants ─────────────────────────────────────────── */

.sku {
  font-family: "SF Mono", "Fira Code", "Cascadia Code", monospace;
  font-size: 0.8125rem;
  color: #6b7280;
}

.price {
  font-variant-numeric: tabular-nums;
  font-weight: 600;
}

.inventory {
  font-variant-numeric: tabular-nums;
}

/* ── Badge ─────────────────────────────────────────────────── */

.badge {
  display: inline-block;
  padding: 0.125rem 0.5rem;
  border-radius: 999px;
  font-size: 0.75rem;
  font-weight: 500;
}

.badge--available {
  background: #d1fae5;
  color: #065f46;
}

.badge--unavailable {
  background: #fee2e2;
  color: #991b1b;
}

/* ── Table footer ──────────────────────────────────────────── */

.table-footer {
  padding: 0.625rem 1rem;
  margin: 0;
  font-size: 0.8125rem;
  color: #9ca3af;
  border-top: 1px solid #f3f4f6;
}

/* ── Empty state ───────────────────────────────────────────── */

.empty-state {
  padding: 3rem 1rem;
  text-align: center;
  color: #9ca3af;
  font-size: 0.9375rem;
  border: 1px dashed #d0d5dd;
  border-radius: 8px;
}

/* ── Skeleton (loading fallback) ───────────────────────────── */

.table-skeleton {
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 1rem;
}

.skeleton-row {
  height: 2.5rem;
  background: linear-gradient(90deg, #f0f0f0 25%, #e0e0e0 50%, #f0f0f0 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
  margin-bottom: 0.5rem;
  border-radius: 4px;
}

.skeleton-row:last-child {
  margin-bottom: 0;
}

@keyframes shimmer {
  0% {
    background-position: 200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

